import { Menu as MenuPrimitive } from "@base-ui/react/menu";
import * as stylex from "@stylexjs/stylex";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { menuStyles } from "./menu.styles";

interface MenuProps extends PropsWithStylex<MenuPrimitive.Root.Props> {
	variant?: "default" | "destructive";
}
const Menu = MenuPrimitive.Root;

function MenuTrigger({
	style,
	...props
}: PropsWithStylex<MenuPrimitive.Trigger.Props>) {
	const renderedStyles = stylex.props(menuStyles.trigger, style);
	return <MenuPrimitive.Trigger {...renderedStyles} {...props} />;
}

type MenuPopupProps = PropsWithStylex<
	MenuPrimitive.Popup.Props & {
		align?: "start" | "center" | "end";
		sideOffset?: number;
	}
>;

function MenuPopup({
	align = "start",
	style,
	sideOffset = 4,
	...props
}: MenuPopupProps) {
	const renderedStyles = stylex.props(menuStyles.popup, style);
	return (
		<MenuPrimitive.Portal>
			<MenuPrimitive.Positioner align={align} sideOffset={sideOffset}>
				<MenuPrimitive.Popup {...renderedStyles} {...props} />
			</MenuPrimitive.Positioner>
		</MenuPrimitive.Portal>
	);
}

type MenuItemProps = PropsWithStylex<
	MenuPrimitive.Item.Props & {
		variant?: "default" | "destructive";
	}
>;

function MenuItem({ style, variant = "default", ...props }: MenuItemProps) {
	const renderedStyles = stylex.props(
		menuStyles.item,
		variant === "destructive" && menuStyles.itemDestructive,
		style,
	);

	return <MenuPrimitive.Item {...renderedStyles} {...props} />;
}

type MenuSeparatorProps = PropsWithStylex<MenuPrimitive.Separator.Props>;

function MenuSeparator({ style, ...props }: MenuSeparatorProps) {
	const renderedStyles = stylex.props(menuStyles.separator, style);
	return <MenuPrimitive.Separator {...renderedStyles} {...props} />;
}

type MenuGroupLabelProps = PropsWithStylex<
	MenuPrimitive.GroupLabel.Props & {
		inset?: boolean;
	}
>;

function MenuGroupLabel({ inset, style, ...props }: MenuGroupLabelProps) {
	const renderedStyles = stylex.props(
		menuStyles.groupLabel,
		inset && menuStyles.inset,
		style,
	);
	return <MenuPrimitive.GroupLabel {...renderedStyles} {...props} />;
}

type MenuShortcutProps = PropsWithStylex<{ children?: React.ReactNode }>;

function MenuShortcut({ children, style }: MenuShortcutProps) {
	const renderedStyles = stylex.props(menuStyles.shortcut, style);
	return <span {...renderedStyles}>{children}</span>;
}

export type {
	MenuGroupLabelProps,
	MenuItemProps,
	MenuPopupProps,
	MenuProps,
	MenuSeparatorProps,
	MenuShortcutProps,
};
export {
	Menu,
	MenuGroupLabel,
	MenuItem,
	MenuPopup,
	MenuPrimitive as MenuBase,
	MenuSeparator,
	MenuShortcut,
	MenuTrigger,
};

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	fontSize,
	fontWeight,
	letterSpacing,
	spacing,
	zIndex,
} from "@/lib/theme/tokens.stylex";

export const menuStyles = stylex.create({
	trigger: {
		display: "inline-flex",
		alignItems: "center",
		justifyContent: "center",
		cursor: "pointer",
		backgroundColor: "transparent",
		appearance: "none",
		border: "none",
		padding: 0,
		outline: "none",
		borderWidth: 0,
		fontFamily: "inherit",
		fontSize: "inherit",
		color: "inherit",
		borderRadius: borderRadius.medium,
		transition: "background-color 0.15s ease, box-shadow 0.15s ease",
		":focus-visible": {
			boxShadow: `0 0 0 2px ${theme.borderStrong}`,
		},
	},
	popup: {
		backgroundColor: theme.surface,
		borderWidth: 1,
		borderStyle: "solid",
		borderColor: theme.borderSubtle,
		borderRadius: borderRadius.large,
		boxShadow: theme.shadowXl,
		zIndex: zIndex.dropdown,
		padding: spacing.xsmall,
		display: "flex",
		gap: spacing[1],
		flexDirection: "column",
		minWidth: 224,
		overflow: "hidden",
		outline: "none",
	},
	item: {
		display: "flex",
		alignItems: "center",
		gap: spacing.small,
		minHeight: 24,
		padding: `${spacing.xsmall} ${spacing.small}`,
		borderRadius: theme.borderRadius,
		color: theme.contentPrimary,
		fontSize: fontSize.small,
		fontWeight: fontWeight.medium,
		lineHeight: 1.2,
		textDecoration: "none",
		textAlign: "left",
		border: "none",
		backgroundColor: "transparent",
		cursor: "pointer",
		appearance: "none",
		outline: "none",
		transition: "background-color 0.15s ease, color 0.15s ease",
		":hover": {
			backgroundColor: theme.backgroundSubtle,
			color: theme.contentPrimary,
		},
		":focus-visible": {
			backgroundColor: theme.backgroundSubtle,
			color: theme.contentPrimary,
			boxShadow: `0 0 0 2px ${theme.borderStrong} inset`,
		},
		":active": {
			backgroundColor: theme.borderSubtle,
		},
	},
	itemDestructive: {
		color: theme.sentimentNegative,
		":hover": {
			backgroundColor: theme.sentimentNegativeSubtle,
			color: theme.sentimentNegative,
		},
		":focus-visible": {
			backgroundColor: theme.sentimentNegativeSubtle,
			color: theme.sentimentNegative,
			boxShadow: `0 0 0 2px ${theme.sentimentNegative} inset`,
		},
		":active": {
			backgroundColor: theme.sentimentNegativeSubtle,
		},
	},
	separator: {
		height: 1,
		backgroundColor: theme.borderSubtle,
		border: "none",
	},
	groupLabel: {
		padding: `${spacing.small} ${spacing.medium} ${spacing.xsmall}`,
		fontSize: fontSize.xsmall,
		fontWeight: fontWeight.semibold,
		color: theme.contentSecondary,
		textTransform: "uppercase",
		letterSpacing: letterSpacing.wide,
	},
	inset: {
		paddingLeft: 40,
	},
	shortcut: {
		marginLeft: "auto",
		color: theme.contentDisabled,
		fontSize: fontSize.xsmall,
		fontWeight: fontWeight.medium,
	},
});
